import logo from './logo.svg';
import './App.css';
import React from 'react';
import DeckGL from '@deck.gl/react';
import {LineLayer} from '@deck.gl/layers';

const MAPBOX_ACCESS_TOKEN = 'pk.eyJ1IjoidmVudG9saW5lIiwiYSI6ImNsbjByOXR6ZDBrYmcybG15enIwODduazMifQ.ubROrEjjoWsUAHdFR15M7g';

// Viewport settings
const INITIAL_VIEW_STATE = {
  longitude: -122.41669,
  latitude: 37.7853,
  zoom: 13,
  pitch: 0,
  bearing: 0
};


// Data to be used by the LineLayer
const data = [
  {sourcePosition: [-122.41669, 37.7853], targetPosition: [-122.41669, 37.781]}
];


function App() {

  const layers = [
    new LineLayer({id: 'line-layer', data})
  ];



  return (


    <div className="App">
      <DeckGL
    initialViewState={INITIAL_VIEW_STATE}
    controller={true}
    layers={layers} />
    </div>
  );
}

export default App;
